-- Step 1: Change status to varchar first
ALTER TABLE `vlogger_inquiries` CHANGE COLUMN `status` `status` VARCHAR(50) NOT NULL DEFAULT 'not_sent';
-- Step 2: Update status values
UPDATE `vlogger_inquiries` SET `status` = 'not_sent' WHERE `status` IN ('Pending', 'pending');
UPDATE `vlogger_inquiries` SET `status` = 'sent' WHERE `status` = 'Sent';
UPDATE `vlogger_inquiries` SET `status` = 'responded' WHERE `status` = 'Responded';
UPDATE `vlogger_inquiries` SET `status` = 'no_reply' WHERE `status` = 'Archived';
-- Step 3: Rename platform -> vloggerPlatform with correct enum
ALTER TABLE `vlogger_inquiries` CHANGE COLUMN `platform` `vloggerPlatform` ENUM('youtube','tiktok','facebook','instagram','other') NOT NULL DEFAULT 'youtube';
-- Step 4: Rename contactEmail -> email
ALTER TABLE `vlogger_inquiries` CHANGE COLUMN `contactEmail` `email` VARCHAR(320) NULL;
-- Step 5: Rename status -> inquiryStatus with correct enum
ALTER TABLE `vlogger_inquiries` CHANGE COLUMN `status` `inquiryStatus` ENUM('not_sent','sent','responded','no_reply','declined') NOT NULL DEFAULT 'not_sent';
-- Step 6: Rename deadlineAt -> deadline
ALTER TABLE `vlogger_inquiries` CHANGE COLUMN `deadlineAt` `deadline` TIMESTAMP NULL;
-- Step 7: Rename notes -> internalNotes
ALTER TABLE `vlogger_inquiries` CHANGE COLUMN `notes` `internalNotes` TEXT NULL;
-- Step 8: Add missing columns
ALTER TABLE `vlogger_inquiries`
  ADD COLUMN IF NOT EXISTS `channelName` VARCHAR(255) NULL,
  ADD COLUMN IF NOT EXISTS `subscriberCount` VARCHAR(100) NULL,
  ADD COLUMN IF NOT EXISTS `evidenceTier` ENUM('confirmed_violation','documented_evidence','under_investigation') NOT NULL DEFAULT 'under_investigation',
  ADD COLUMN IF NOT EXISTS `violationDate` VARCHAR(50) NULL,
  ADD COLUMN IF NOT EXISTS `agency` VARCHAR(255) NULL,
  ADD COLUMN IF NOT EXISTS `violationSummary` TEXT NULL,
  ADD COLUMN IF NOT EXISTS `startYear` VARCHAR(10) NULL,
  ADD COLUMN IF NOT EXISTS `estimatedRevenue` VARCHAR(100) NULL,
  ADD COLUMN IF NOT EXISTS `dateSent` TIMESTAMP NULL,
  ADD COLUMN IF NOT EXISTS `sentLetterText` TEXT NULL;
-- Step 9: Remove old columns not in original schema
ALTER TABLE `vlogger_inquiries`
  DROP COLUMN IF EXISTS `channelUrl`,
  DROP COLUMN IF EXISTS `deadlineDays`,
  DROP COLUMN IF EXISTS `lastTemplateUsed`;

